// Nodo: "Process News" - VERSIÓN CORREGIDA
const inputData = $input.all()[0].json;

let rawText = "";

console.log("📰 Datos recibidos:", Object.keys(inputData));

// Extraer el texto de la respuesta de Jina Reader
if (inputData.data && typeof inputData.data === 'string') {
    rawText = inputData.data;
    console.log(`✅ Texto extraído de 'data': ${rawText.length} caracteres`);
} 
else if (typeof inputData === 'string') {
    rawText = inputData;
    console.log(`✅ Texto extraído de string: ${rawText.length} caracteres`);
}
else if (inputData.raw_text) {
    rawText = inputData.raw_text;
    console.log(`✅ Texto extraído de raw_text: ${rawText.length} caracteres`);
}
else if (inputData.text) {
    rawText = inputData.text;
    console.log(`✅ Texto extraído de text: ${rawText.length} caracteres`);
}

// Limpiar caracteres de escape
rawText = rawText.replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\');

console.log(`📄 Primeros 300 caracteres: ${rawText.substring(0, 300)}`);

// Extraer noticias
let articles = [];
const lines = rawText.split('\n');

const highImpactKeywords = [
    "ecb", "fed", "interest rate", "gdp", "cpi", "nfp", "non-farm",
    "employment", "retail sales", "pmi", "manufacturing", "trump",
    "powell", "jolts", "unemployment", "inflation"
];

for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.includes('investinglive.com/news/') || line.includes('forexlive.com')) {
        let title = "";
        const urlMatch = line.match(/https?:\/\/[^\/]+\/news\/([^\/]+)/);
        if (urlMatch) {
            title = urlMatch[1].replace(/-/g, ' ').replace(/\d{8}$/, '').trim();
            title = title.charAt(0).toUpperCase() + title.slice(1);
        }

        if (!title || title.length < 5) continue;

        let relevance = "low";
        const titleLower = title.toLowerCase();
        for (const keyword of highImpactKeywords) {
            if (titleLower.includes(keyword)) {
                relevance = "high";
                break;
            }
        }

        let currency = "";
        if (titleLower.includes("us") || titleLower.includes("fed")) currency = "USD";
        else if (titleLower.includes("euro") || titleLower.includes("ecb")) currency = "EUR";
        else if (titleLower.includes("uk") || titleLower.includes("boe")) currency = "GBP";
        else if (titleLower.includes("japan") || titleLower.includes("boj")) currency = "JPY";
        else if (titleLower.includes("swiss")) currency = "CHF";

        articles.push({
            title: title.substring(0, 150),
            currency: currency,
            relevance: relevance,
            // url: line.trim()
        });
    }
}

// Eliminar duplicados
const uniqueArticles = [];
const titles = new Set();
for (const article of articles) {
    if (!titles.has(article.title)) {
        titles.add(article.title);
        uniqueArticles.push(article);
    }
}

uniqueArticles.sort((a, b) => {
    if (a.relevance === "high" && b.relevance !== "high") return -1;
    return 0;
});

const topArticles = uniqueArticles.slice(0, 10);

console.log(`📰 ${topArticles.length} noticias procesadas`);
topArticles.forEach(a => console.log(`   - ${a.currency}: ${a.title.substring(0, 50)} (${a.relevance})`));

return [{
    json: {
        news: topArticles,
        news_count: topArticles.length,
        high_impact_count: topArticles.filter(a => a.relevance === "high").length
    }
}];
